VALUES
  ('heelevel3-7ec62a85-moex-00056', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-114-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'single_choice', '下列何種情形國家不負損害賠償責任？', '["甲國家公園管理機關因颱風警報，在所屬國家公園登山口公告禁止入山，乙因假期難得，仍冒 險登山而發生山難", "丙機關設立之公園鞦韆已經壞損，不堪使用，故在該鞦韆旁標示不得使用，丁仍讓其未成年之 子女戊使用，戊不幸拋飛而受有重傷", "主管機關平日未巡視公園樹木狀況，因強烈颱風來襲，致樹木倒塌壓傷路過之民眾", "土地登記機關因可歸責之事由，發生登記錯誤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "229", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00057', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-114-3082b5f1', 'sub-heelevel3-7ec62a85-03', NULL, 'single_choice', '依司法實務見解，公共事業之設施穿越私有土地之地下，致逾越所有權人社會責任所應忍受範圍， 形成個人之特別犧牲時，下列敘述何者正確？', '["土地所有權人得請求需用土地人向主管機關申請徵收地上權", "所有權人之土地所有權並未受剝奪，故應忍受此一財產權社會義務的合法限制", "此屬財產權之違法侵害，當事人應請求除去侵害", "無法律則無徵收補償，若法律未有規定時，所有權人不得請求需用土地人向主管機關申請徵收"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "229", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00058', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-113-de0a21a2', 'sub-heelevel3-7ec62a85-01', NULL, 'essay', '甲欲殺乙男，於夜間打算潛入乙男住處，但因光線昏暗，誤入丙女住宅。
甲進入臥室後，便抽刀砍向床上的丙女，丙女被砍了一刀後驚醒並大聲
呼救，甲立即發現自己砍錯人，慌忙逃離現場，丙女受的刀傷經醫治後
則無大礙。刑法上應如何評價甲之行為？（30 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "a63e79e72b19", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "325", "s": "1015", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00059', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-113-de0a21a2', 'sub-heelevel3-7ec62a85-01', NULL, 'essay', '甲在 A飯店大廳沙發區休憩，甫抵達飯店的乙將嶄新的名牌行李箱置放
於沙發旁，逕自前往櫃臺辦理入住。甲見狀竟心生歹念，跑到門口對排
班計程車司機丙謊稱該行李箱為其所有，要丙幫忙將該行李箱搬上車。
丙不疑有他，正要推走行李箱時，被乙發現攔阻，丙即表示自己乃受甲
所託，甲見犯行被發現，立即下車逃逸，門口服務生丁見狀上前阻擋，
甲竟揮拳將丁擊倒後離開。試問刑法上應如何評價上開事實？（35 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "a63e79e72b19", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "325", "s": "1015", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00060', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-113-de0a21a2', 'sub-heelevel3-7ec62a85-01', NULL, 'essay', '甲無故侵入鄰居乙家，向乙討債，一言不合，甲竟持棍棒毆打乙的頭部
要害後逃逸，乙之母親 A剛從外返家見狀，詢問乙為何人所傷，乙乃將
其被甲傷害的經過詳細告知 A，嗣乙因傷重氣絕身亡；甲逃亡在外，某
日約其好友 B喝酒，酒後詳細告知 B其如何殺害乙之經過。嗣經檢察官
偵查終結，起訴甲犯有殺人罪嫌，在法院審理中，檢察官聲請傳喚證人
A、B到庭作證。證人 A、B在審判中到庭具結後證稱甲如何殺害乙之經
過綦詳。試問：證人 A、B 二人在審判中之言詞陳述，得否作為證明甲
殺害乙之證據？（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "a63e79e72b19", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "325", "s": "1015", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00061', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-113-de0a21a2', 'sub-heelevel3-7ec62a85-01', NULL, 'essay', '地方法院 A法官判決甲強盜罪刑，甲提起第二審上訴，經高等法院 B法
官之合議庭判決駁回上訴，甲提起第三審上訴，經最高法院撤銷原判決
發回更審，更一審 C法官之合議庭撤銷第一審判決，仍改判甲強盜罪刑，
甲再提起第三審上訴，適逢 B 法官榮調最高法院。試問：B 法官就甲的
第三審上訴案件，應否自行迴避？（15 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "a63e79e72b19", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "325", "s": "1015", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
