  ('heelevel3-7ec62a85-moex-00064', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-113-3a7b2121', 'sub-heelevel3-7ec62a85-02', NULL, 'single_choice', '以行政學的發展演進之歷史來看，下列理論何者最適合被歸類在修正理論時期（約1930～1960年）？', '["權變理論", "激勵保健理論", "科學管理理論", "社會系統理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "3c5fbab47917", "answer_pdf_sha1": "ea9f06b2527a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "325", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('heelevel3-7ec62a85-moex-00065', 'heelevel3-7ec62a85', 'heelevel3-7ec62a85-moex-113-3a7b2121', 'sub-heelevel3-7ec62a85-02', NULL, 'single_choice', '「組織的存在，有賴於組織與成員之間彼此保持貢獻與滿足的平衡」，下列何者符合前述論點？', '["組織的激勵作用有助於成員持續投入", "組織提供的誘因，是指有形的物質報償", "貢獻與滿足之間存在一個不變的均衡點", "組織可透過權威來補充誘因的不足"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:20+00:00", "source_pdf_sha1": "3c5fbab47917", "answer_pdf_sha1": "ea9f06b2527a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "325", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法律廉政"}'::jsonb, NULL)
